noncompliant:
class Base { virtual ~Base() {} };
class Derived : public virtual Base {
public:
    void derived_method();
};

void function(Base* base_ptr) {
    // Noncompliant: using static_cast with virtual inheritance
    Derived* derived_ptr = static_cast<Derived*>(base_ptr);

    // Noncompliant: using reinterpret_cast
    Derived* derived_ptr2 = reinterpret_cast<Derived*>(base_ptr);

    // Noncompliant: using C-style cast
    Derived* derived_ptr3 = (Derived*)base_ptr;
}

compliant:
class Base { virtual ~Base() {} };
class Derived : public virtual Base {
public:
    void derived_method();
};

void function(Base* base_ptr) {
    // Compliant: using dynamic_cast for virtual inheritance
    Derived* derived_ptr = dynamic_cast<Derived*>(base_ptr);
    if (derived_ptr != nullptr) {
        derived_ptr->derived_method();
    }
}

// Alternative: avoid casting by using virtual functions
class Base {
public:
    virtual ~Base() {}
    virtual void do_operation() = 0;
};

class Derived : public virtual Base {
public:
    void do_operation() override { /* implementation */ }
};
